cd "C:\Users\ADMINI~1\AppData\Local\Temp\e2e-young-marriage-1828-j92hglmg\results" && node -e "
const fs = require('fs');
const data = JSON.parse(fs.readFileSync('log_017.json', 'utf8'));
const results = data.payload.results;
const candidates = results.map(r => {
  const persons = r.gedcomx.persons;
  const child = persons.find(p => p.ark === r.recordId || p.id === r.primaryId);
  const father = persons.find(p => {
    const rel = r.gedcomx.relationships && r.gedcomx.relationships.find(rel => rel.type === 'ParentChild' && rel.child === (child ? child.id : null) && rel.parent === p.id);
    return rel && p.gender === 'Male';
  });
  const mother = persons.find(p => {
    const rel = r.gedcomx.relationships && r.gedcomx.relationships.find(rel => rel.type === 'ParentChild' && rel.child === (child ? child.id : null) && rel.parent === p.id);
    return rel && p.gender === 'Female';
  });
  const christening = r.events && r.events.find(e => e.type === 'Christening');
  const fatherName = father ? ((father.names[0].given || '') + ' ' + (father.names[0].surname || '')).trim() : 'unknown';
  const motherName = mother ? ((mother.names[0].given || '') + ' ' + (mother.names[0].surname || '')).trim() : 'unknown';
  return {
    name: r.personName,
    date: christening ? christening.date : 'unknown',
    father: fatherName,
    mother: motherName
  };
});
candidates.forEach(c => console.log(c.date + ' | ' + c.name + ' | father: ' + c.father + ' | mother: ' + c.mother));
"

